export {
  SaturationSliderPropsContext as PropsContext,
  SaturationSliderRoot as Root,
  SaturationSliderThumb as Thumb,
  SaturationSliderTrack as Track,
  useSaturationSliderPropsContext as usePropsContext,
} from "./saturation-slider"
export type {
  SaturationSliderRootProps as RootProps,
  SaturationSliderThumbProps as ThumbProps,
  SaturationSliderTrackProps as TrackProps,
} from "./saturation-slider"

import { defineComponentSlotStyle } from "@yamada-ui/react"
import { hueSliderStyle } from "../hue-slider"
import { sliderStyle } from "../slider"

export const saturationSliderStyle = defineComponentSlotStyle({
  base: {
    root: {
      aspectRatio: "16 / 9",
      boxShadow: "inner",
      isolation: "isolate",
      maxW: "full",
      p: "calc({thumb-size} / 2)",
      rounded: "{root-rounded}",
      touchAction: "none",
      w: "full",
      _readOnly: { layerStyle: "readOnly" },
      _disabled: { layerStyle: "disabled" },
    },
    thumb: {
      ...sliderStyle.base?.thumb,
      ...hueSliderStyle.base?.thumb,
      boxSize: "{thumb-size}",
      left: "{--x, 0%}",
      position: "absolute",
      rounded: "{thumb-rounded}",
      top: "{--y, 0%}",
      transform: "translate(-50%, -50%)",
    },
    track: {
      boxSize: "full",
      cursor: {
        base: "pointer",
        _readOnly: "default",
        _disabled: "not-allowed",
      },
      position: "relative",
    },
  },

  props: {
    /**
     * The shape of the thumb.
     *
     * @default 'circle'
     */
    shape: {
      circle: {
        root: {
          ...sliderStyle.props?.shape.circle.root,
          "--root-rounded": "radii.l2",
        },
      },
      rounded: {
        root: {
          ...sliderStyle.props?.shape.rounded.root,
          "--root-rounded": "radii.l2",
        },
      },
      square: {
        root: {
          ...sliderStyle.props?.shape.square.root,
          "--root-rounded": "0",
        },
      },
    },
  },

  sizes: {
    xs: {
      root: { "--thumb-size": hueSliderStyle.sizes?.xs.root["--thumb-size"] },
    },
    sm: {
      root: { "--thumb-size": hueSliderStyle.sizes?.sm.root["--thumb-size"] },
    },
    md: {
      root: { "--thumb-size": hueSliderStyle.sizes?.md.root["--thumb-size"] },
    },
    lg: {
      root: { "--thumb-size": hueSliderStyle.sizes?.lg.root["--thumb-size"] },
    },
    xl: {
      root: { "--thumb-size": hueSliderStyle.sizes?.xl.root["--thumb-size"] },
    },
  },

  defaultProps: {
    size: "md",
    shape: "circle",
  },
})

export type SaturationSliderStyle = typeof saturationSliderStyle

import { vi } from "vitest"
import { a11y, page, render } from "#test/browser"
import { SaturationSlider } from "."
import { noop } from "@yamada-ui/react"

const mockRect = (
  el: HTMLElement | SVGElement,
  rect: Partial<DOMRect>,
): (() => void) => {
  const original = el.getBoundingClientRect
  el.getBoundingClientRect = () =>
    ({
      bottom: 0,
      height: 0,
      left: 0,
      right: 0,
      toJSON: noop,
      top: 0,
      width: 0,
      x: 0,
      y: 0,
      ...rect,
    }) as DOMRect
  return () => {
    el.getBoundingClientRect = original
  }
}

const keyDown = (el: HTMLElement | SVGElement, key: string) => {
  el.dispatchEvent(new KeyboardEvent("keydown", { key, bubbles: true }))
}

const pointer = (
  target: EventTarget,
  type: "pointerdown" | "pointermove" | "pointerup",
  init: PointerEventInit,
) => {
  target.dispatchEvent(new PointerEvent(type, { bubbles: true, ...init }))
}

describe("<SaturationSlider />", () => {
  test("renders component correctly", async () => {
    await a11y(<SaturationSlider.Root />)
  })

  test("sets `displayName` correctly", () => {
    expect(SaturationSlider.Root.displayName).toBe("SaturationSliderRoot")
    expect(SaturationSlider.Track.displayName).toBe("SaturationSliderTrack")
    expect(SaturationSlider.Thumb.displayName).toBe("SaturationSliderThumb")
  })

  test("sets `className` correctly", async () => {
    await render(
      <SaturationSlider.Root
        data-testid="slider"
        trackProps={{ "data-testid": "track" }}
      />,
    )
    await expect
      .element(page.getByTestId("slider"))
      .toHaveClass("ui-saturation-slider__root")
    await expect
      .element(page.getByTestId("track"))
      .toHaveClass("ui-saturation-slider__track")
    await expect
      .element(page.getByRole("slider"))
      .toHaveClass("ui-saturation-slider__thumb")
  })

  test("sets aria attributes correctly", async () => {
    await render(<SaturationSlider.Root defaultValue={[120, 0.5, 0.8]} />)

    const thumb = page.getByRole("slider")
    await expect.element(thumb).toHaveAttribute("aria-valuenow", "50")
    await expect.element(thumb).toHaveAttribute("aria-valuemin", "0")
    await expect.element(thumb).toHaveAttribute("aria-valuemax", "100")
    await expect
      .element(thumb)
      .toHaveAttribute("aria-roledescription", "2D slider")
  })

  test("uses custom aria-valuetext", async () => {
    await render(
      <SaturationSlider.Root
        aria-valuetext="custom text"
        defaultValue={[0, 0.5, 0.5]}
      />,
    )

    await expect
      .element(page.getByRole("slider"))
      .toHaveAttribute("aria-valuetext", "custom text")
  })

  test("uses getAriaValueText", async () => {
    const getAriaValueText = vi.fn().mockReturnValue("custom aria")

    await render(
      <SaturationSlider.Root
        defaultValue={[0, 0.5, 0.5]}
        getAriaValueText={getAriaValueText}
      />,
    )

    await expect
      .element(page.getByRole("slider"))
      .toHaveAttribute("aria-valuetext", "custom aria")
    expect(getAriaValueText).toHaveBeenCalledWith([0, 0.5, 0.5])
  })

  test("keyboard ArrowRight increases saturation", async () => {
    const onChange = vi.fn()

    await render(
      <SaturationSlider.Root
        defaultValue={[0, 0.5, 0.5]}
        onChange={onChange}
      />,
    )

    keyDown(page.getByRole("slider").element(), "ArrowRight")

    expect(onChange).toHaveBeenCalledWith([0, 0.51, 0.5])
  })

  test("keyboard ArrowLeft decreases saturation", async () => {
    const onChange = vi.fn()

    await render(
      <SaturationSlider.Root
        defaultValue={[0, 0.5, 0.5]}
        onChange={onChange}
      />,
    )

    keyDown(page.getByRole("slider").element(), "ArrowLeft")

    expect(onChange).toHaveBeenCalledWith([0, 0.49, 0.5])
  })

  test("keyboard ArrowUp increases brightness", async () => {
    const onChange = vi.fn()

    await render(
      <SaturationSlider.Root
        defaultValue={[0, 0.5, 0.5]}
        onChange={onChange}
      />,
    )

    keyDown(page.getByRole("slider").element(), "ArrowUp")

    expect(onChange).toHaveBeenCalledWith([0, 0.5, 0.51])
  })

  test("keyboard ArrowDown decreases brightness", async () => {
    const onChange = vi.fn()

    await render(
      <SaturationSlider.Root
        defaultValue={[0, 0.5, 0.5]}
        onChange={onChange}
      />,
    )

    keyDown(page.getByRole("slider").element(), "ArrowDown")

    expect(onChange).toHaveBeenCalledWith([0, 0.5, 0.49])
  })

  test("keyboard does not change value when disabled", async () => {
    const onChange = vi.fn()

    await render(
      <SaturationSlider.Root
        defaultValue={[0, 0.5, 0.5]}
        disabled
        onChange={onChange}
      />,
    )

    keyDown(page.getByRole("slider").element(), "ArrowRight")

    expect(onChange).not.toHaveBeenCalled()
  })

  test("keyboard does not change value when readOnly", async () => {
    const onChange = vi.fn()

    await render(
      <SaturationSlider.Root
        defaultValue={[0, 0.5, 0.5]}
        readOnly
        onChange={onChange}
      />,
    )

    keyDown(page.getByRole("slider").element(), "ArrowRight")

    expect(onChange).not.toHaveBeenCalled()
  })

  test("clamps saturation value within bounds via keyboard", async () => {
    const onChange = vi.fn()

    await render(
      <SaturationSlider.Root defaultValue={[0, 1, 0.5]} onChange={onChange} />,
    )

    keyDown(page.getByRole("slider").element(), "ArrowRight")

    expect(onChange).toHaveBeenCalledWith([0, 1, 0.5])
  })

  test("clamps brightness value within bounds via keyboard", async () => {
    const onChange = vi.fn()

    await render(
      <SaturationSlider.Root defaultValue={[0, 0.5, 0]} onChange={onChange} />,
    )

    keyDown(page.getByRole("slider").element(), "ArrowDown")

    expect(onChange).toHaveBeenCalledWith([0, 0.5, 0])
  })

  test("disabled SaturationSlider renders correctly", async () => {
    await render(<SaturationSlider.Root disabled />)

    await expect
      .element(page.getByRole("slider"))
      .toHaveAttribute("aria-disabled")
  })

  test("readonly SaturationSlider renders correctly", async () => {
    await render(<SaturationSlider.Root readOnly />)

    await expect
      .element(page.getByRole("slider"))
      .toHaveAttribute("aria-readonly")
  })

  test("thumb has tabIndex 0 when interactive", async () => {
    await render(<SaturationSlider.Root />)

    await expect
      .element(page.getByRole("slider"))
      .toHaveAttribute("tabindex", "0")
  })

  test("thumb has tabIndex -1 when disabled", async () => {
    await render(<SaturationSlider.Root disabled />)

    await expect
      .element(page.getByRole("slider"))
      .toHaveAttribute("tabindex", "-1")
  })

  test("respects custom step", async () => {
    const onChange = vi.fn()

    await render(
      <SaturationSlider.Root
        defaultValue={[0, 0.5, 0.5]}
        step={0.1}
        onChange={onChange}
      />,
    )

    keyDown(page.getByRole("slider").element(), "ArrowRight")

    expect(onChange).toHaveBeenCalledWith([0, 0.6, 0.5])
  })

  test("renders with controlled value", async () => {
    await render(<SaturationSlider.Root value={[200, 0.8, 0.6]} />)

    await expect
      .element(page.getByRole("slider"))
      .toHaveAttribute("aria-valuenow", "80")
  })

  test("renders with custom children", async () => {
    await render(
      <SaturationSlider.Root data-testid="slider">
        <SaturationSlider.Track data-testid="custom-track">
          <SaturationSlider.Thumb data-testid="custom-thumb" />
        </SaturationSlider.Track>
      </SaturationSlider.Root>,
    )

    await expect.element(page.getByTestId("custom-track")).toBeInTheDocument()
    await expect.element(page.getByTestId("custom-thumb")).toBeInTheDocument()
  })

  test("sets name on hidden input", async () => {
    const { container } = await render(
      <SaturationSlider.Root name="color-saturation" />,
    )

    const input = container.querySelector("input[name='color-saturation']")
    expect(input).toBeInTheDocument()
  })

  test("sets id on hidden input", async () => {
    const { container } = await render(
      <SaturationSlider.Root id="saturation-input" />,
    )

    const input = container.querySelector("input#saturation-input")
    expect(input).toBeInTheDocument()
  })

  test("pointer interaction triggers onChangeStart and onChangeEnd", async () => {
    const onChangeStart = vi.fn()
    const onChangeEnd = vi.fn()

    await render(
      <SaturationSlider.Root
        defaultValue={[120, 0.5, 0.5]}
        trackProps={{ "data-testid": "track" }}
        onChangeEnd={onChangeEnd}
        onChangeStart={onChangeStart}
      />,
    )

    const track = page.getByTestId("track").element()
    const cleanup = mockRect(track, {
      bottom: 200,
      height: 200,
      left: 0,
      width: 200,
    })

    pointer(track, "pointerdown", { clientX: 100, clientY: 100 })
    expect(onChangeStart).toHaveBeenCalledWith([120, 0.5, 0.5])

    pointer(window, "pointerup", { clientX: 140, clientY: 60 })
    await expect.poll(() => onChangeEnd.mock.calls.length).toBe(1)
    expect(onChangeEnd).toHaveBeenCalledWith([120, 0.7, 0.7])

    cleanup()
  })

  test("pointer interaction triggers onChange on move", async () => {
    const onChange = vi.fn()

    await render(
      <SaturationSlider.Root
        defaultValue={[120, 0.5, 0.5]}
        trackProps={{ "data-testid": "track" }}
        onChange={onChange}
      />,
    )

    const track = page.getByTestId("track").element()
    const cleanup = mockRect(track, {
      bottom: 200,
      height: 200,
      left: 0,
      width: 200,
    })

    pointer(track, "pointerdown", { clientX: 100, clientY: 100 })
    pointer(window, "pointermove", { clientX: 160, clientY: 40 })
    await expect.poll(() => onChange.mock.calls.length).toBeGreaterThan(0)
    expect(onChange).toHaveBeenCalledWith([120, 0.8, 0.8])

    pointer(window, "pointerup", { clientX: 160, clientY: 40 })

    cleanup()
  })

  test("pointer interaction does not trigger callbacks when disabled", async () => {
    const onChangeStart = vi.fn()
    const onChange = vi.fn()
    const onChangeEnd = vi.fn()

    await render(
      <SaturationSlider.Root
        defaultValue={[0, 0.5, 0.5]}
        disabled
        trackProps={{ "data-testid": "track" }}
        onChange={onChange}
        onChangeEnd={onChangeEnd}
        onChangeStart={onChangeStart}
      />,
    )

    const track = page.getByTestId("track").element()
    const cleanup = mockRect(track, {
      bottom: 200,
      height: 200,
      left: 0,
      width: 200,
    })

    pointer(track, "pointerdown", { clientX: 100, clientY: 100 })
    pointer(window, "pointermove", { clientX: 120, clientY: 80 })
    pointer(window, "pointerup", { clientX: 120, clientY: 80 })

    expect(onChangeStart).not.toHaveBeenCalled()
    expect(onChange).not.toHaveBeenCalled()
    expect(onChangeEnd).not.toHaveBeenCalled()

    cleanup()
  })
})

"use client"

import type { HTMLStyledProps, ThemeProps, Merge } from "@yamada-ui/react"
import type { SaturationSliderStyle } from "./saturation-slider.style"
import type {
  UseSaturationSliderProps,
  UseSaturationSliderReturn,
} from "./use-saturation-slider"
import { useMemo } from "react"
import { createSlotComponent, styled } from "@yamada-ui/react"
import { saturationSliderStyle } from "./saturation-slider.style"
import { useSaturationSlider } from "./use-saturation-slider"

interface ComponentContext extends Pick<
  UseSaturationSliderReturn,
  "getThumbProps" | "getTrackProps"
> {}

export interface SaturationSliderRootProps
  extends
    Merge<HTMLStyledProps, UseSaturationSliderProps>,
    ThemeProps<SaturationSliderStyle> {
  /**
   * Props for the input element.
   */
  inputProps?: HTMLStyledProps<"input">
  /**
   * Props for the thumb element.
   */
  thumbProps?: SaturationSliderThumbProps
  /**
   * Props for the track element.
   */
  trackProps?: SaturationSliderTrackProps
}

const {
  ComponentContext,
  PropsContext: SaturationSliderPropsContext,
  useComponentContext,
  usePropsContext: useSaturationSliderPropsContext,
  withContext,
  withProvider,
} = createSlotComponent<
  SaturationSliderRootProps,
  SaturationSliderStyle,
  ComponentContext
>("saturation-slider", saturationSliderStyle)

export { SaturationSliderPropsContext, useSaturationSliderPropsContext }

/**
 * `SaturationSlider` is a component used to allow the user to select a color saturation.
 *
 * @see https://yamada-ui.com/docs/components/saturation-slider
 */
export const SaturationSliderRoot = withProvider<
  "input",
  SaturationSliderRootProps
>(({ children, inputProps, thumbProps, trackProps, ...rest }) => {
  const { getInputProps, getRootProps, getThumbProps, getTrackProps } =
    useSaturationSlider(rest)
  const computedChildren = useMemo(() => {
    if (children) return children

    return (
      <SaturationSliderTrack {...trackProps}>
        <SaturationSliderThumb {...thumbProps} />
      </SaturationSliderTrack>
    )
  }, [children, thumbProps, trackProps])
  const context = useMemo(
    () => ({ getThumbProps, getTrackProps }),
    [getThumbProps, getTrackProps],
  )

  return (
    <ComponentContext value={context}>
      <styled.div {...getRootProps()}>
        <styled.input {...getInputProps(inputProps)} />
        {computedChildren}
      </styled.div>
    </ComponentContext>
  )
}, "root")()

export interface SaturationSliderTrackProps extends HTMLStyledProps {}

export const SaturationSliderTrack = withContext<
  "div",
  SaturationSliderTrackProps
>("div", "track")(undefined, (props) => {
  const { getTrackProps } = useComponentContext()

  return getTrackProps(props)
})

export interface SaturationSliderThumbProps extends HTMLStyledProps {}

export const SaturationSliderThumb = withContext<
  "div",
  SaturationSliderThumbProps
>("div", "thumb")(undefined, (props) => {
  const { getThumbProps } = useComponentContext()

  return getThumbProps(props)
})

"use client"

import type { KeyboardEvent } from "react"
import type {
  HTMLProps,
  HTMLRefAttributes,
  PropGetter,
  Point,
} from "@yamada-ui/react"
import type { FieldProps } from "../field"
import { useCallback } from "react"
import {
  mergeProps,
  clampNumber,
  cx,
  handlerAll,
  mergeRefs,
  roundNumberToStep,
  visuallyHiddenAttributes,
  runKeyAction,
} from "@yamada-ui/react"
import { useControllableState } from "../../hooks/use-controllable-state"
import { usePanEvent } from "../../hooks/use-pan-event"
import { useI18n } from "../../providers/i18n-provider"
import { useFieldProps } from "../field"

function clampValue(value: [number, number, number]) {
  return [
    clampNumber(value[0], 0, 360),
    clampNumber(value[1], 0, 1),
    clampNumber(value[2], 0, 1),
  ] as [number, number, number]
}

export interface UseSaturationSliderProps
  extends
    Omit<HTMLProps, "defaultValue" | "onChange" | "ref">,
    HTMLRefAttributes<"input">,
    FieldProps {
  /**
   * The initial value of the saturation slider.
   *
   * @default [0, 0, 1]
   */
  defaultValue?: [number, number, number]
  /**
   * The base `id` to use for the slider.
   */
  id?: string
  /**
   * The name attribute of the hidden `input` field.
   * This is particularly useful in forms.
   */
  name?: string
  /**
   * The step in which increments or decrements have to be made.
   *
   * @default 0.01
   */
  step?: number
  /**
   * The value of the saturation slider.
   */
  value?: [number, number, number]
  /**
   * This is used to format the value so that screen readers
   * can speak out a more human-friendly value.
   *
   * It is used to set the `aria-valuetext` property of the input.
   */
  getAriaValueText?: (value: [number, number, number]) => string | undefined
  /**
   * Function called whenever the saturation slider value changes.
   */
  onChange?: (value: [number, number, number]) => void
  /**
   * Function called when the user is done selecting a new value.
   */
  onChangeEnd?: (value: [number, number, number]) => void
  /**
   * Function called when the user starts selecting a new value.
   */
  onChangeStart?: (value: [number, number, number]) => void
}

export const useSaturationSlider = (props: UseSaturationSliderProps = {}) => {
  const {
    props: {
      id,
      ref,
      name,
      "aria-labelledby": ariaLabelledBy,
      "aria-valuetext": ariaValueText,
      defaultValue = [0, 0, 1],
      disabled,
      getAriaValueText,
      readOnly,
      required,
      step = 0.01,
      value: valueProp,
      onChange: onChangeProp,
      onChangeEnd,
      onChangeStart,
      ...rest
    },
    ariaProps,
    dataProps,
    eventProps,
  } = useFieldProps(props)
  const { t } = useI18n("saturationSlider")
  const [value, setValue] = useControllableState({
    defaultValue,
    value: valueProp,
    onChange: onChangeProp,
  })
  const [h, s, v] = clampValue(value)
  const interactive = !(disabled || readOnly)
  const [_, getPanEventProps] = usePanEvent<HTMLDivElement>({
    onEnd: (_, point, rect) => {
      if (!interactive) return

      const panValue = getPanValue(point, rect)

      onChangeEnd?.(panValue)
    },
    onMove: (_, point, rect) => {
      if (!interactive) return

      const panValue = getPanValue(point, rect)

      setValue(panValue)
    },
    onStart: (_, point, rect) => {
      if (!interactive) return

      const panValue = getPanValue(point, rect)

      onChangeStart?.(value)
      setValue(panValue)
    },
  })

  const onChange = useCallback(
    ([h, s, v]: [number, number, number]) => {
      if (!interactive) return

      s = clampNumber(s, 0, 1)
      v = clampNumber(v, 0, 1)

      setValue([h, s, v])
    },
    [interactive, setValue],
  )

  const getPanValue = useCallback(
    (
      { x, y }: Point,
      { bottom, height, left, width }: DOMRect,
    ): [number, number, number] => {
      const diff = { x: x - left, y: bottom - y }
      const percent = { x: diff.x / width, y: diff.y / height }
      const clamp = {
        x: clampNumber(percent.x, 0, 1),
        y: clampNumber(percent.y, 0, 1),
      }
      const s = roundNumberToStep(clamp.x, 0, step)
      const v = roundNumberToStep(clamp.y, 0, step)

      return [h, parseFloat(s), parseFloat(v)]
    },
    [h, step],
  )

  const onKeyDown = useCallback(
    (ev: KeyboardEvent<HTMLDivElement>) => {
      runKeyAction(ev, {
        ArrowDown: () => onChange([h, s, v - step]),
        ArrowLeft: () => onChange([h, s - step, v]),
        ArrowRight: () => onChange([h, s + step, v]),
        ArrowUp: () => onChange([h, s, v + step]),
      })
    },
    [h, onChange, s, step, v],
  )

  const getRootProps: PropGetter = useCallback(
    (props = {}) => {
      const merged = mergeProps(dataProps, rest, props)()

      return {
        ...merged,
        style: {
          ...rest.style,
          ...props.style,
          "--x": `${Math.abs(s * 100)}%`,
          "--y": `${Math.abs(100 - v * 100)}%`,
          backgroundColor: `hsl(${h}, 100%, 50%)`,
          backgroundImage:
            "linear-gradient(0deg, #000, transparent), linear-gradient(90deg, #fff, transparent)",
        },
        onBlur: handlerAll(props.onBlur, eventProps.onBlur),
        onFocus: handlerAll(props.onFocus, eventProps.onFocus),
      }
    },
    [dataProps, eventProps, h, rest, s, v],
  )

  const getInputProps: PropGetter<"input"> = useCallback(
    (props = {}) => ({
      ...visuallyHiddenAttributes,
      ...dataProps,
      ...ariaProps,
      id,
      type: "hidden",
      name,
      disabled,
      readOnly,
      required,
      value: [h, s, v].toString(),
      ...props,
      ref: mergeRefs(props.ref, ref),
    }),
    [
      ariaProps,
      dataProps,
      disabled,
      h,
      id,
      name,
      readOnly,
      ref,
      required,
      s,
      v,
    ],
  )

  const getTrackProps: PropGetter = useCallback(
    (props = {}) => getPanEventProps({ ...dataProps, ...props }),
    [dataProps, getPanEventProps],
  )

  const getThumbProps: PropGetter = useCallback(
    (props = {}) => ({
      ...dataProps,
      ...ariaProps,
      "aria-label": t("Saturation and brightness thumb"),
      "aria-roledescription": "2D slider",
      "aria-valuemax": 100,
      "aria-valuemin": 0,
      "aria-valuenow": s * 100,
      "aria-valuetext":
        ariaValueText ??
        getAriaValueText?.(value) ??
        t("Saturation {saturation}%, Brightness {brightness}%", {
          brightness: v * 100,
          saturation: s * 100,
        }),
      role: "slider",
      tabIndex: interactive ? 0 : -1,
      ...props,
      "aria-labelledby": cx(props["aria-labelledby"], ariaLabelledBy),
      onKeyDown: handlerAll(props.onKeyDown, onKeyDown),
    }),
    [
      ariaLabelledBy,
      ariaProps,
      ariaValueText,
      dataProps,
      getAriaValueText,
      interactive,
      onKeyDown,
      s,
      t,
      v,
      value,
    ],
  )

  return {
    setValue,
    value,
    getInputProps,
    getRootProps,
    getThumbProps,
    getTrackProps,
    onChange,
  }
}

export type UseSaturationSliderReturn = ReturnType<typeof useSaturationSlider>
